   181→
   182→   
   183→
   184→    const handleBackLocation = (e) =>{
   185→        e.stopPropagation();
   186→        window.history.back();
   187→    }
   188→
   189→    const hanldeClickComments = (e) =>{
   190→        e.stopPropagation();
   191→        setShowCommentsContainer(true);
   192→    }
   193→
   194→    const handleCLoseComments = () =>{
   195→        setShowCommentsContainer(false);
   196→    }
   197→
   198→
   199→    useEffect(() =>{
   200→        setLikesCount(postData?.likesCount)
   201→        setBookmarkCounts(postData?.bookmarksCount)
   202→        setIsliked(postData?.isLiked)
   203→        setIsBookmarked(postData?.isBookmarked)
   204→    }, [postData])
   205→
   206→    useEffect(() => {
   207→        const hideBackBttn = () =>{
   208→            setShowBackButton(false);
   209→            if(timeOutRef.current){
   210→                clearTimeout(timeOutRef.current)
   211→            }
   212→            
   213→            timeOutRef.current = setTimeout(() =>{
   214→                setShowBackButton(true)
   215→            }, 300)
   216→        }
   217→
   218→        document.addEventListener('scroll', hideBackBttn, true);
   219→        return () =>{
   220→            if(timeOutRef.current){
   221→                clearTimeout(timeOutRef.current)
   222→            }
   223→            document.removeEventListener('scroll', hideBackBttn, true)
   224→            
   225→        }
   226→    }, [])
   227→
   228→    // useEffect(() =>{
   229→    //     console.log(followsData)
   230→    // }, [followsData])
   231→
   232→    if(isLoading){
   233→        return(
   234→            <div className="contentView-loading-container">
   235→                <MoonLoader loading={isLoading} size={25}/>
   236→            </div>
   237→        )
   238→    }
   239→
   240→    return(
   241→        <>
   242→        {showCommentsContainer && (
   243→                <AnimatePresence>
   244→                <CommentSection onclose={handleCLoseComments} postId={postData?.journalId} receiverId={postData?.userId}/>
   245→                </AnimatePresence>
   246→            )}
   247→        <div ref={contentRef} className="content-viewer-container">
