   263→                    </div>
   264→                    <p style={{padding: '0', margin: '0', fontSize: '1.2rem', fontWeight: '600'}}>Post</p>
   265→                </motion.div>
   266→                </AnimatePresence>
   267→            )}
   268→
   269→            <div className="content-title-container">
   270→                {showBookmarkedMessage &&(
