   276→                    transition={{type: 'tween', damping: 25, stiffness: 200, ease: 'easeInOut', duration: 0.1}}
   277→                    >
   278→                        {bookmarkedMessage}
   279→                    </motion.div>
   280→                    </AnimatePresence>
   281→                )}
   282→                <p className="content-title">{postData?.title}</p>
   283→
   284→                <div className="content-metadata-container">
