   286→                        <img src={postData?.avatar || '/assets/profile.jpg'} className="content-avatar" alt="user avatar" />
   287→                    </div>
   288→                    <div onClick={(e) => handleclickUserProfile(e, user?.userData?.[0].id, postData?.userId)} className="content-owner-name">
   289→                        {postData?.name}
   290→                    </div>
   291→                    <VerifiedBadge badge={postData?.badge} size={16} />
   292→
   293→                    {postData?.userId !== user?.userData?.[0].id && (
   294→                        <div onClick={(e) => debounceClickFollow(e, postData?.userId, user?.userData?.[0].id)} className={followsData?.isFollowing ? 'unfollow-bttn' : 'follow-bttn'}>
   295→                           {followsData?.isFollowing ? 'Unfollow' : 'Follow'}
   296→                        </div>
   297→                    )}
   298→                    
   299→                    <div className="content-created">
   300→                        <p>
   301→                            {new Date(postData?.created_at).toLocaleDateString('en-US', {
   302→                            month: 'long',
   303→                            day: '2-digit',
   304→                            year: 'numeric',
   305→                        })} at       
   306→                        </p>
   307→                        <p>
   308→                            {new Date(postData?.created_at).toLocaleTimeString('en-US', {
   309→                                hour: '2-digit',
   310→                                minute: '2-digit'
   311→                            })}
   312→                        </p>
   313→                    </div>
   314→
   315→                    <div className="separator">
   316→                        •
   317→                    </div>
   318→                    <div className="read-time">
   319→                        {CalculateText(postData?.wholeText)}
   320→                    </div>
   321→            </div>
   322→
   323→            <div className="icons-container">
   324→                {cardIcons.map((icon, index) => (
   325→                    <div key={index} className="content-viewer-icons">
   326→                        {icon.likeAction && (
   327→                            <div onClick={(e) => icon.likeAction(e, postData?.journalId, postData?.userId, user?.userData?.[0].image_url, user?.userData?.[0].name, user?.userData?.[0].user_email)} className={icon.className}>
   328→                                {icon.labelLike && icon.labelLike(isLiked)}  
   329→                            </div>
   330→                        )}
   331→                        {icon.commentAction && (
   332→                            <div onClick={(e) => icon.commentAction(e, postData?.journalId)} className={icon.className}> 
   333→                                {icon.label}
   334→                            </div>
   335→                        )}
   336→                        {icon.bookmarkAction && (
   337→                            <div onClick={(e) => icon.bookmarkAction(e, postData?.journalId)} className={icon.className}>
   338→                                {icon.labelBookmark && icon.labelBookmark(isBookmarked)}
   339→                            </div>
   340→                        )}
   341→                        <div>{icon.likeCount && icon.likeCount(likesCount)}</div>
   342→                        <div>{icon.commentsCount && icon.commentsCount(postData?.commentsCount)}</div>
   343→                        <div>{icon.bookmarksCount && icon.bookmarksCount(bookmarkCounts)}</div>
   344→                    </div> 
   345→                ))}
   346→                
   347→            </div>
   348→
   349→            </div>
   350→
   351→            <LexicalComposer initialConfig={{
   352→                namespace: "ContentViewer",
   353→                theme: theme,
   354→                editable: false,
   355→                editorState: postData?.content,
   356→                nodes: [HeadingNode, ImageNode],
   357→                onError(error){
   358→                    throw error
   359→                },
   360→            }}>
   361→                <RichTextPlugin
   362→                contentEditable={<ContentEditable 
   363→                    className="content"
   364→                    />
   365→                }
   366→                ErrorBoundary={LexicalErrorBoundary}
   367→                />
   368→            </LexicalComposer>
   369→        </div>
   370→        </>
   371→    )
   372→}
   373→
   374→export default ContentView;

