     1→const VerifiedBadge = ({ badge, size = 18 }) => {
     2→    if (!badge) return null;
     3→
     4→    const colors = {
     5→        legend: {
     6→            bg: '#FFD700',
     7→            icon: '#FFFFFF',
     8→            glow: 'rgba(255, 215, 0, 0.35)',
     9→        },
    10→        og: {
    11→            bg: '#9B59FF',
    12→            icon: '#FFFFFF',
    13→            glow: 'rgba(155, 89, 255, 0.35)',
    14→        },
    15→    };
    16→
    17→    const scheme = colors[badge];
    18→    if (!scheme) return null;
    19→
    20→    return (
    21→        <span
    22→            className="verified-badge"
    23→            title={badge === 'legend' ? 'Legend' : 'OG'}
    24→            style={{
    25→                display: 'inline-flex',
    26→                alignItems: 'center',
    27→                justifyContent: 'center',
    28→                flexShrink: 0,
    29→                filter: `drop-shadow(0 0 4px ${scheme.glow})`,
    30→            }}
    31→        >
    32→            <svg
    33→                width={size}
    34→                height={size}
    35→                viewBox="0 0 24 24"
    36→                fill="none"
    37→                xmlns="http://www.w3.org/2000/svg"
    38→            >
    39→                {/* Starburst / shield shape */}
    40→                <path
    41→                    d="M12 1.5L14.09 3.64L17 2.9L17.18 5.88L19.8 7.32L18.46 10.02L19.8 12.72L17.18 14.16L17 17.14L14.09 16.4L12 18.54L9.91 16.4L7 17.14L6.82 14.16L4.2 12.72L5.54 10.02L4.2 7.32L6.82 5.88L7 2.9L9.91 3.64L12 1.5Z"
    42→                    fill={scheme.bg}
    43→                />
    44→                {/* Checkmark */}
    45→                <path
    46→                    d="M9.5 11.5L11 13.5L15 9"
    47→                    stroke={scheme.icon}
    48→                    strokeWidth="2"
    49→                    strokeLinecap="round"
    50→                    strokeLinejoin="round"
    51→                />
    52→            </svg>
    53→        </span>
    54→    );
    55→};
    56→
    57→export default VerifiedBadge;
    58→

