     1→const CalculateText = (text) => {
     2→    const wordPerMin = 150 //avg reading speed
     3→    const words = text.trim().split(/\s+/).length; //split the it by spaces using /\s+/
     4→    // console.log(words)
     5→    const minutes = words/wordPerMin;
     6→    const readingTime = Math.ceil(minutes);
     7→
     8→    if(readingTime > 1){
     9→        return `${readingTime} mins read`
    10→    }
    11→
    12→    return `${readingTime} min read`;
    13→}
    14→
    15→export default CalculateText;

